import{_ as t,c as s,o as r,ah as o}from"./chunks/framework.RCw5T9E9.js";const c=JSON.parse('{"title":"Update settings","description":"","frontmatter":{"title":"Update settings"},"headers":[],"relativePath":"options/update_settings.md","filePath":"options/update_settings.md"}'),n={name:"options/update_settings.md"};function a(i,e,l,g,h,p){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="update-settings" tabindex="-1">Update settings <a class="header-anchor" href="#update-settings" aria-label="Permalink to &quot;Update settings&quot;">​</a></h1><p>Below <strong>Customize</strong> in <strong>Options → General</strong> you will find <strong>Search Parameters</strong> and <strong>Auto Refresh</strong>. They persist with the rest of the profile (see <a href="/qa-tools/docs/options/settings_management.html">Settings management</a>).</p><hr><h2 id="search-parameters" tabindex="-1">Search Parameters <a class="header-anchor" href="#search-parameters" aria-label="Permalink to &quot;Search Parameters&quot;">​</a></h2><p>Global rules for <strong>text search</strong> across tabs that share the same parameters (<strong>Props</strong>, <strong>Network</strong>, <strong>Pinia</strong> — field debounce/min length).</p><h3 id="search-debounce-ms" tabindex="-1">Search Debounce (ms) <a class="header-anchor" href="#search-debounce-ms" aria-label="Permalink to &quot;Search Debounce (ms)&quot;">​</a></h3><p><strong>Delay after typing stops</strong> before the query applies. Avoids firing on every keystroke.</p><p>Typical allowed range <strong>100–1000</strong> ms (default near <strong>300</strong>). Lower = snappier but more churn; higher = calmer on heavy tables.</p><h3 id="minimum-search-length" tabindex="-1">Minimum Search Length <a class="header-anchor" href="#minimum-search-length" aria-label="Permalink to &quot;Minimum Search Length&quot;">​</a></h3><p><strong>Minimum characters</strong> before filtering runs. Shorter input behaves like an empty query (usually full list).</p><p>Allowed <strong>1–10</strong> (often <strong>2</strong>). <strong>1</strong> reacts on first char; higher reduces noisy short prefixes.</p><p>These fields are <strong>shared</strong> — one place updates <strong>Props</strong>, <strong>Network</strong>, and <strong>Pinia</strong> consumers.</p><hr><h2 id="auto-refresh" tabindex="-1">Auto Refresh <a class="header-anchor" href="#auto-refresh" aria-label="Permalink to &quot;Auto Refresh&quot;">​</a></h2><p><strong>Enable auto refresh</strong> polls <strong>component tree</strong> views and the <strong>Pinia Stores</strong> table on an interval (<strong>Refresh Interval</strong>: <strong>1, 2, 5, 10, 30</strong> seconds).</p><p>Ticks <strong>do not stack</strong> if a refresh is already running.</p><h3 id="panel-visibility" tabindex="-1">Panel visibility <a class="header-anchor" href="#panel-visibility" aria-label="Permalink to &quot;Panel visibility&quot;">​</a></h3><p>Polling runs <strong>only while the inspector panel is visible</strong> (embedded UI considered active). <strong>Hiding</strong> the panel <strong>stops</strong> timers; showing it again <strong>resumes</strong> if <strong>Enable auto refresh</strong> stays on.</p><p>Primarily affects <strong>Props</strong> and <strong>Stores</strong>.</p><h3 id="props-storm-protection" tabindex="-1">Props storm protection <a class="header-anchor" href="#props-storm-protection" aria-label="Permalink to &quot;Props storm protection&quot;">​</a></h3><p>On <strong>Props</strong>, besides the configured interval, very frequent tree snapshots from the page can trigger <strong>throttling</strong>: temporarily <strong>pauses applying</strong> bursts so the UI stays responsive. There is <strong>no</strong> user toggle — it is a protective layer.</p><p><strong>Network</strong> is <strong>not</strong> on this auto-refresh schedule — it follows page network events.</p><p>Use Auto Refresh when the app mutates the tree or stores often and you want updates without hammering <strong>Refresh</strong> manually. Very short intervals on huge trees can cost CPU — try <strong>10–30</strong> s if needed.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/options/settings_management.html">Settings management</a></li><li><a href="/qa-tools/docs/options/display_mode.html">Display modes</a></li></ul>',26)])])}const u=t(n,[["render",a]]);export{c as __pageData,u as default};
